"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[2072],{48918:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>s,default:()=>d,frontMatter:()=>i,metadata:()=>a,toc:()=>c});var o=t(74848),r=t(28453);const i={slug:"DefconQ at Iverson College - The Return to Milden Hall",title:"DefconQ at Iverson College - The Return to Milden Hall",authors:["alexander"],hide_table_of_contents:!0,tags:["kdb/q","DefconQ","Iverson College","Kenneth Iverson","Community Meetup"]},s=void 0,a={permalink:"/blog/DefconQ at Iverson College - The Return to Milden Hall",source:"@site/blog/2026-04-22-defconq-at-iversoncollege/index.md",title:"DefconQ at Iverson College - The Return to Milden Hall",description:"If you\u2019ve been around the KDB/Q ecosystem for a while, chances are you\u2019ve come across the legendary Iverson College. Founded by former KX Librarian Stephen Taylor in honour of Kenneth E. Iverson, the inventor of APL, the college has been running since 2011. After a brief hiatus between 2018 and 2023, it made a strong return in 2024. This year DefconQ joins forces with Stephen to reconvene the College at one of its favourite venues: Milden Hall.",date:"2026-04-22T00:00:00.000Z",tags:[{label:"kdb/q",permalink:"/blog/tags/kdb-q"},{label:"DefconQ",permalink:"/blog/tags/defcon-q"},{label:"Iverson College",permalink:"/blog/tags/iverson-college"},{label:"Kenneth Iverson",permalink:"/blog/tags/kenneth-iverson"},{label:"Community Meetup",permalink:"/blog/tags/community-meetup"}],readingTime:2.295,hasTruncateMarker:!0,authors:[{name:"Alexander Unterrainer",title:"DefconQ, KDB/Q Developer, Consultant",url:"https://github.com/AUnterrainer",imageURL:"/img/alex.jpeg",key:"alexander"}],frontMatter:{slug:"DefconQ at Iverson College - The Return to Milden Hall",title:"DefconQ at Iverson College - The Return to Milden Hall",authors:["alexander"],hide_table_of_contents:!0,tags:["kdb/q","DefconQ","Iverson College","Kenneth Iverson","Community Meetup"]},unlisted:!1,prevItem:{title:"DefconQ Community Discord Server",permalink:"/blog/DefconQ Community Discord Server"},nextItem:{title:"DefconQ x Squarepoint - Networking Event",permalink:"/blog/DefconQ x Squarepoint - Networking Event"}},l={authorsImageUrls:[void 0]},c=[];function h(e){const n={a:"a",br:"br",em:"em",img:"img",p:"p",strong:"strong",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:"If you\u2019ve been around the KDB/Q ecosystem for a while, chances are you\u2019ve come across the legendary Iverson College. Founded by former KX Librarian Stephen Taylor in honour of Kenneth E. Iverson, the inventor of APL, the college has been running since 2011. After a brief hiatus between 2018 and 2023, it made a strong return in 2024. This year DefconQ joins forces with Stephen to reconvene the College at one of its favourite venues: Milden Hall."}),"\n",(0,o.jsx)(n.p,{children:(0,o.jsx)(n.img,{alt:"DefconQ at Iverson College",src:t(38380).A+"",width:"1536",height:"1024"})}),"\n",(0,o.jsx)(n.p,{children:"While previous meetings spanned a range of Iversonian programming languages, this year\u2019s meeting will be entirely on KDB/Q. That said, the principles and concepts explored remain broadly applicable across the wider family of vector languages, with future meetings set to expand again."}),"\n",(0,o.jsxs)(n.p,{children:["Iverson College is half conference, half house party. There\u2019s no rigid agenda, no back-to-back slide decks, and no passive audience. The participants ",(0,o.jsx)(n.em,{children:"are"})," the programme. It\u2019s a collaborative, immersive environment where ideas are shared, challenged, and built upon in real time. Inspired by the ethos outlined in the college\u2019s foundations, the focus is on deep learning through interaction, not presentation. Even though there will be no pre-set agenda, there will be a handful of presentations, knowledge-sharing sessions, and story times from some of the most experienced voices in the industry. We shall bring together some of the smartest, most experienced kdb developers."]}),"\n",(0,o.jsx)(n.p,{children:"With the recent release of KDB-X and the introduction of modules, this year\u2019s meeting of the College will centre around building the modules the community actually needs. And we won\u2019t just talk about them, we\u2019ll start implementing them. The goal is to lay the groundwork for a shared, community-driven codebase that can be reused and extended in real production environments."}),"\n",(0,o.jsx)(n.p,{children:"The setting for all of this is Milden Hall, a Tudor barn in Suffolk that has hosted some of the college's most memorable meetings. It\u2019s a unique workspace that fosters the kind of close collaboration and focused work the event is known for. The ticket price of \xa31300 includes meals (we bring our own chefs) and hostel-level accommodation, ensuring everyone can fully immerse themselves in the experience without distraction. Places are strictly limited to just 20 attendees, keeping the environment intimate, focused, and highly interactive."}),"\n",(0,o.jsxs)(n.p,{children:[(0,o.jsx)(n.strong,{children:"When"}),": 6 - 10 September, 2026 ",(0,o.jsx)(n.br,{}),"\n",(0,o.jsx)(n.strong,{children:"Where"}),": ",(0,o.jsx)(n.a,{href:"https://www.thehall-milden.co.uk",children:"Milden Hall, Suffolk"}),"  ",(0,o.jsx)(n.br,{}),"\n",(0,o.jsx)(n.strong,{children:"Price"}),": 1300\xa3 ",(0,o.jsx)(n.br,{}),"\n",(0,o.jsx)(n.strong,{children:"Signup here"}),": You can secure your ticket by sending an email to ",(0,o.jsx)(n.a,{href:"mailto:dean@iversoncollege.com",children:"dean@iversoncollege.com"})," and we will send you the payment instructions"]}),"\n",(0,o.jsxs)(n.p,{children:["Some impressions of the 2024 edition of the Iverson College in Cambridge, captured by ",(0,o.jsx)(n.a,{href:"https://www.mikiy.com",children:"Miki Yamanouchi"}),", a London based photographer and film maker."]}),"\n",(0,o.jsxs)(n.p,{children:["You can learn more about Iverson College and explore previous editions ",(0,o.jsx)(n.a,{href:"https://iversoncollege.com",children:"here"}),"."]}),"\n",(0,o.jsx)("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/w-MyzJLHfmc?si=-Wi6KgzPeNpyIr5-",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:!0})]})}function d(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(h,{...e})}):h(e)}},38380:(e,n,t)=>{t.d(n,{A:()=>o});const o=t.p+"assets/images/DefconQ@IversonCollege-0530bd3c2b5f0ea5aa9aa96d84ee3831.png"},28453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>a});var o=t(96540);const r={},i=o.createContext(r);function s(e){const n=o.useContext(i);return o.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:s(e.components),o.createElement(i.Provider,{value:n},e.children)}}}]);